package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() {
    JsonElement element = mock(JsonElement.class);
    when(element.isJsonObject()).thenReturn(true);
    when(element.toString()).thenReturn("{\"key\":\"value\"}");
    // Cast to JsonObject to simulate the actual returned type
    JsonObject jsonObject = mock(JsonObject.class);

    // Mock the cast by making element a JsonObject instance
    // We cannot cast a mock of JsonElement directly, so create a spy of JsonObject
    JsonObject spyObject = spy(JsonObject.class);
    doReturn(true).when(spyObject).isJsonObject();

    JsonObject result = spyObject.getAsJsonObject();

    assertSame(spyObject, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement element = mock(JsonElement.class);
    when(element.isJsonObject()).thenReturn(false);
    when(element.toString()).thenReturn("notJsonObject");

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonObject);
    assertEquals("Not a JSON Object: notJsonObject", exception.getMessage());
  }
}
